{
  render: (args) => {
    const [value, setValue] = useState<DateValue | null>(parseDate("2025-01-15"));
    const minDate = today(getLocalTimeZone());
    const isInvalid = value !== null && value.compare(minDate) < 0;

    return (
      <div className="flex flex-col items-center gap-4">
        <CalendarTemplate
          {...args}
          aria-label="Event date"
          isInvalid={isInvalid}
          value={value}
          onChange={setValue}
        />
        {isInvalid ? (
          <p className="text-sm text-danger">Date must be today or in the future</p>
        ) : (
          <Description className="text-center">Select a future date</Description>
        )}
      </div>
    );
  },
}

{
  render: (args) => {
    const now = today(getLocalTimeZone());
    const blockedRanges = [
      [now.add({days: 2}), now.add({days: 5})],
      [now.add({days: 12}), now.add({days: 13})],
    ] as const;

    const isDateUnavailable = (date: DateValue) => {
      return blockedRanges.some(
        ([start, end]) => date.compare(start) >= 0 && date.compare(end) <= 0,
      );
    };

    return (
      <div className="flex flex-col items-center gap-4">
        <RangeCalendarTemplate
          {...args}
          aria-label="Trip dates"
          defaultValue={{end: now.add({days: 9}), start: now.add({days: 6})}}
          isDateUnavailable={isDateUnavailable}
        />
        <Description className="text-center">Some days are unavailable</Description>
      </div>
    );
  },
}

{
  render: (args) => {
    const now = today(getLocalTimeZone());
    const [value, setValue] = useState<DateRange>({
      end: now.add({days: 14}),
      start: now.add({days: 6}),
    });
    const isInvalid = value.end.compare(value.start) > 7;

    return (
      <div className="flex flex-col items-center gap-4">
        <RangeCalendarTemplate
          {...args}
          aria-label="Trip dates"
          isInvalid={isInvalid}
          value={value}
          onChange={setValue}
        />
        {isInvalid ? (
          <p className="text-sm text-danger">Maximum stay duration is 1 week</p>
        ) : (
          <Description className="text-center">Select a stay of up to 7 days</Description>
        )}
      </div>
    );
  },
}

